"use client"

import { ReactNode } from "react"
import {
	Table,
	TableBody,
	TableCell,
	TableHead,
	TableHeader,
	TableRow,
} from "@/components/ui/table"
import { cn } from "@/lib/utils"
import { Skeleton } from "@/components/ui/skeleton"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import {
	Pagination,
	PaginationContent,
	PaginationItem,
	PaginationNext,
	PaginationPrevious,
} from "@/components/ui/pagination"

type Align = "left" | "center" | "right"

export type DataTableColumn<T> = {
	key: keyof T | string
	label: string
	align?: Align
	className?: string
	width?: string
	render?: (row: T, index: number) => ReactNode
}

export type DataTablePagination = {
	page: number
	totalPages: number
	totalItems?: number
	pageSize?: number
	pageSizeOptions?: number[]
	hasNext?: boolean
	hasPrev?: boolean
	onPageChange?: (page: number) => void
	onPageSizeChange?: (pageSize: number) => void
}

type DataTableProps<T> = {
	data: T[]
	columns: DataTableColumn<T>[]
	loading?: boolean
	emptyMessage?: string
	rowKey?: (row: T, index: number) => string
	caption?: ReactNode
	striped?: boolean
	onRowClick?: (row: T) => void
	footer?: ReactNode
	pagination?: DataTablePagination
}

const alignMap: Record<Align, string> = {
	left: "text-left",
	center: "text-center",
	right: "text-right",
}

export function DataTable<T>({
	data,
	columns,
	loading = false,
	emptyMessage = "No records found.",
	rowKey,
	caption,
	striped = true,
	onRowClick,
	footer,
	pagination,
}: DataTableProps<T>) {
	const getKey = (row: T, index: number) => {
		if (rowKey) return rowKey(row, index)
		const fallback = (row as any)?._id ?? (row as any)?.id
		return fallback ? String(fallback) : String(index)
	}

	const pageSizeOptions = pagination?.pageSizeOptions ?? [5, 10, 20, 50]
	const canGoPrev = pagination ? (pagination.hasPrev ?? pagination.page > 1) : false
	const canGoNext = pagination
		? pagination.hasNext ?? pagination.page < pagination.totalPages
		: false

	const handlePrev = () => {
		if (!pagination?.onPageChange || !pagination) return
		const nextPage = Math.max(1, pagination.page - 1)
		pagination.onPageChange(nextPage)
	}

	const handleNext = () => {
		if (!pagination?.onPageChange || !pagination) return
		const nextPage = Math.min(pagination.page + 1, pagination.totalPages)
		pagination.onPageChange(nextPage)
	}

	if (loading) {
		return (
			<div className="rounded-lg border bg-white">
				<Table>
					<TableHeader>
						<TableRow>
							{columns.map((col) => (
								<TableHead key={String(col.key)}>{col.label}</TableHead>
							))}
						</TableRow>
					</TableHeader>
					<TableBody>
						{Array.from({ length: 5 }).map((_, i) => (
							<TableRow key={i}>
								{columns.map((col) => (
									<TableCell key={String(col.key)}>
										<Skeleton className="h-4 w-full" />
									</TableCell>
								))}
							</TableRow>
						))}
					</TableBody>
				</Table>
			</div>
		)
	}

	if (!data.length) {
		return (
			<div className="rounded-lg border bg-white p-6 text-center text-sm text-muted-foreground">
				{emptyMessage}
			</div>
		)
	}

	return (
		<div className="overflow-hidden rounded-lg border bg-white">
			<Table>
				{caption ? (
					<caption className="px-4 py-3 text-left text-sm text-muted-foreground">
						{caption}
					</caption>
				) : null}
				<TableHeader>
					<TableRow>
						{columns.map((col) => (
							<TableHead
								key={String(col.key)}
								className={cn(col.align && alignMap[col.align], col.className)}
								style={col.width ? { width: col.width } : undefined}
							>
								{col.label}
							</TableHead>
						))}
					</TableRow>
				</TableHeader>

				<TableBody>
					{data.map((row, index) => (
						<TableRow
							key={getKey(row, index)}
							className={cn(
								striped && index % 2 === 1 && "bg-slate-50/40",
								onRowClick && "cursor-pointer hover:bg-slate-50"
							)}
							onClick={onRowClick ? () => onRowClick(row) : undefined}
						>
							{columns.map((col) => (
								<TableCell
									key={String(col.key)}
									className={cn(col.align && alignMap[col.align], col.className)}
								>
									{col.render ? col.render(row, index) : (row as any)[col.key as string]}
								</TableCell>
							))}
						</TableRow>
					))}
				</TableBody>
			</Table>
			{footer ? <div className="border-t px-4 py-3">{footer}</div> : null}
		</div>
	)
}
