'use client'

import { DataTable, type DataTableColumn } from '@/components/common/DataTable'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationNext,
  PaginationPrevious,
} from '@/components/ui/pagination'
import { cn } from '@/lib/utils'

import { MoreHorizontal, Pencil, Trash } from 'lucide-react'

import { useDepartmentsList } from '../hooks/useDepartmentsList'
import { useDepartmentActions } from '../hooks/useDepartmentActions'
import { Department } from '../types/departments.types'
import { useTextTruncate } from '@/hooks/useTextTruncate'

interface DepartmentsTableProps {
  onEdit?: (department: Department) => void
}

export function DepartmentsTable({ onEdit }: DepartmentsTableProps) {
  const { departments, loading, meta, query, setQuery } = useDepartmentsList()
  const { confirmDelete, loading: isDeleting } = useDepartmentActions()
  const { truncate } = useTextTruncate()

  const handlePageChange = (page: number) => {
    if (!meta) return
    const safe = Math.min(Math.max(page, 1), meta.totalPages)
    setQuery((prev) => ({ ...prev, page: safe }))
  }

  const handleLimitChange = (value: string) => {
    const limit = Number(value)
    setQuery((prev) => ({ ...prev, limit, page: 1 }))
  }

  const columns: DataTableColumn<Department>[] = [
    {
      key: 'title',
      label: 'Title',
      render: (row) => <span className="font-semibold text-slate-900">{row.title}</span>,
    },
    {
      key: 'description',
      label: 'Description',
      render: (row) => (
        <span className="text-sm text-slate-700" title={row.description || ''}>
          {row.description ? truncate(row.description, 70) : 'N/A'}
        </span>
      ),
    },
    {
      key: 'jobsCount',
      label: 'Jobs',
      render: (row) => (
        <Badge variant="secondary" className="font-mono text-xs">
          {row.jobsCount ?? 0} posted
        </Badge>
      ),
    },
    {
      key: 'actions',
      label: 'Actions',
      align: 'right',
      render: (row) => (
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="icon" className="h-8 w-8">
              <MoreHorizontal className="h-4 w-4" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuItem onClick={() => onEdit?.(row)}>
              <Pencil className="mr-2 h-4 w-4" />
              Edit
            </DropdownMenuItem>
            <DropdownMenuItem
              className="text-destructive"
              disabled={isDeleting}
              onClick={() => confirmDelete(row)}
            >
              <Trash className="mr-2 h-4 w-4" />
              Delete
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      ),
    },
  ]

  return (
    <div className="space-y-4">
      <DataTable
        data={departments}
        columns={columns}
        loading={loading}
        striped
        emptyMessage="No departments found."
      />

      <div className="flex flex-wrap items-center justify-between gap-3">
        <div className="text-sm text-muted-foreground">
          Total: {meta?.totalDocs ?? departments.length}
        </div>
        <div className="flex items-center text-sm gap-2">
          Rows per page:{' '}
          <Select value={String(query.limit ?? 10)} onValueChange={handleLimitChange}>
            <SelectTrigger>
              <SelectValue placeholder="Rows" />
            </SelectTrigger>
            <SelectContent>
              {[5, 10, 20, 50].map((opt) => (
                <SelectItem key={opt} value={String(opt)}>
                  {opt}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          <Pagination className="w-auto">
            <PaginationContent>
              <PaginationPrevious
                href="#"
                onClick={(e) => {
                  e.preventDefault()
                  handlePageChange((meta?.page ?? 1) - 1)
                }}
                aria-disabled={!meta?.hasPrevPage}
                className={cn(!meta?.hasPrevPage && 'pointer-events-none opacity-50')}
              />

              <PaginationItem>
                <span className="px-2 text-sm text-muted-foreground">
                  Page {meta?.page ?? 1} of {meta?.totalPages ?? 1}
                </span>
              </PaginationItem>

              <PaginationNext
                href="#"
                onClick={(e) => {
                  e.preventDefault()
                  handlePageChange((meta?.page ?? 1) + 1)
                }}
                aria-disabled={!meta?.hasNextPage}
                className={cn(!meta?.hasNextPage && 'pointer-events-none opacity-50')}
              />
            </PaginationContent>
          </Pagination>
        </div>
      </div>
    </div>
  )
}
