import { useCallback, useEffect, useState } from 'react';
import {
  Department,
  DepartmentQuery,
  PaginatedResponse,
} from '../types/departments.types';
import { getDepartments } from '../services/departments.service';

export function useDepartmentsList(initialQuery?: DepartmentQuery) {
  const [data, setData] =
    useState<PaginatedResponse<Department> | null>(null);
  const [loading, setLoading] = useState(false);

  const [query, setQuery] = useState<DepartmentQuery>({
    page: 1,
    limit: 10,
    sortBy: 'createdAt',
    order: 'desc',
    ...initialQuery,
  });

  const fetchDepartments = useCallback(async () => {
    setLoading(true);
    try {
      const res = await getDepartments(query);
      setData(res.data);
    } finally {
      setLoading(false);
    }
  }, [query]);

  useEffect(() => {
    fetchDepartments();
  }, [fetchDepartments]);

  return {
    departments: data?.docs ?? [],
    meta: data,
    loading,

    query,
    setQuery,
    refetch: fetchDepartments,
  };
}
